     1	using FluentValidation;
     2	using InventoryFlow.Application.Features.Authentication;
     3	using InventoryFlow.Domain.Exceptions;
     4	using Microsoft.AspNetCore.Diagnostics;
     5	using Microsoft.AspNetCore.Mvc;
     6	
     7	namespace InventoryFlow.Api.ExceptionHandling;
     8	
     9	/// <summary>
    10	/// Converts unhandled application exceptions into RFC 7807 problem details responses.
    11	/// </summary>
    12	/// <param name="logger">The logger used to capture unexpected failures.</param>
    13	public sealed class GlobalExceptionHandler(
    14	    ILogger<GlobalExceptionHandler> logger) : IExceptionHandler
    15	{
    16	    /// <inheritdoc />
    17	    public async ValueTask<bool> TryHandleAsync(
    18	        HttpContext httpContext,
    19	        Exception exception,
    20	        CancellationToken cancellationToken)
    21	    {
    22	        if (httpContext.Response.HasStarted)
    23	        {
    24	            logger.LogWarning(
    25	                exception,
    26	                "The response has already started for {RequestMethod} {RequestPath}",
    27	                httpContext.Request.Method,
    28	                httpContext.Request.Path);
    29	
    30	            return false;
    31	        }
    32	
    33	        var statusCode = exception switch
    34	        {
    35	            ValidationException => StatusCodes.Status400BadRequest,
    36	            DomainException => StatusCodes.Status400BadRequest,
    37	            AuthenticationException => StatusCodes.Status401Unauthorized,
    38	            _ => StatusCodes.Status500InternalServerError,
    39	        };
    40	
    41	        logger.LogError(
    42	            exception,
    43	            "Unhandled exception while processing {RequestMethod} {RequestPath}",
    44	            httpContext.Request.Method,
    45	            httpContext.Request.Path);
    46	
    47	        if (exception is ValidationException validationException)
    48	        {
    49	            var validation = new ValidationProblemDetails(validationException.Errors.GroupBy(error => error.PropertyName).ToDictionary(group => group.Key, group => group.Select(error => error.ErrorMessage).ToArray()))
    50	            { Status = statusCode, Title = "One or more validation errors occurred.", Type = "https://tools.ietf.org/html/rfc9110#section-15.5.1" };
    51	            httpContext.Response.StatusCode = statusCode;
    52	            await httpContext.Response.WriteAsJsonAsync(validation, options: null, contentType: "application/problem+json", cancellationToken: cancellationToken);
    53	            return true;
    54	        }
    55	
    56	        var problemDetails = new ProblemDetails
    57	        {
    58	            Status = statusCode,
    59	            Title = statusCode switch { StatusCodes.Status400BadRequest => "A business rule was violated.", StatusCodes.Status401Unauthorized => "Authentication failed.", _ => "An unexpected error occurred." },
    60	            Type = statusCode == StatusCodes.Status400BadRequest
    61	                ? "https://tools.ietf.org/html/rfc9110#section-15.5.1"
    62	                : "https://tools.ietf.org/html/rfc9110#section-15.6.1",
    63	            Detail = exception is DomainException ? exception.Message : null,
    64	        };
    65	
    66	        httpContext.Response.StatusCode = statusCode;
    67	        await httpContext.Response.WriteAsJsonAsync(
    68	            problemDetails,
    69	            options: null,
    70	            contentType: "application/problem+json",
    71	            cancellationToken: cancellationToken);
    72	
    73	        return true;
    74	    }
    75	}
