    92	            .AddRoles<IdentityRole<Guid>>()
    93	            .AddEntityFrameworkStores<ApplicationDbContext>()
    94	            .AddSignInManager()
    95	            .AddDefaultTokenProviders();
    96	
    97	        return services;
    98	    }
    99	}
